import React, { useEffect, useState } from 'react';
import api from '../api';

const VERIFICACION_COLOR = {
  pendiente: '#FFC107',
  aprobado: '#2E7D32',
  rechazado: '#E53935',
};

export default function Usuarios() {
  const [usuarios, setUsuarios] = useState([]);
  const [cargando, setCargando] = useState(true);
  const [filtro, setFiltro] = useState('todos');
  const [conductorSeleccionado, setConductorSeleccionado] = useState(null);

  const cargar = () => {
    api.get('/users/todos')
      .then(res => setUsuarios(res.data))
      .catch(() => {})
      .finally(() => setCargando(false));
  };

  useEffect(() => { cargar(); }, []);

  const verificar = async (uid, estado) => {
    try {
      await api.put(`/users/conductor/${uid}/verificacion`, { estado });
      cargar();
      setConductorSeleccionado(null);
    } catch {
      alert('Error al actualizar verificación');
    }
  };

  const filtrados = filtro === 'todos' ? usuarios : usuarios.filter(u => u.rol === filtro);
  const pendientesVerificacion = usuarios.filter(u => u.rol === 'conductor' && u.estadoVerificacion === 'pendiente').length;

  if (cargando) return <p className="loading">Cargando usuarios...</p>;

  // Modal detalle conductor
  if (conductorSeleccionado) {
    const c = conductorSeleccionado;
    return (
      <div>
        <button onClick={() => setConductorSeleccionado(null)} style={styles.btnVolver}>← Volver</button>
        <h2 className="titulo">Perfil del Conductor</h2>

        <div style={styles.perfilCard}>
          <div style={styles.perfilGrid}>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Nombre completo</span><span style={styles.perfilValor}>{c.nombre}</span></div>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Número de cédula</span><span style={styles.perfilValor}>{c.cedula || '—'}</span></div>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Número de celular</span><span style={styles.perfilValor}>{c.telefono}</span></div>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Placa del taxi</span><span style={styles.perfilValor}>{c.placa || '—'}</span></div>
            <div style={styles.perfilItem}>
              <span style={styles.perfilLabel}>Estado verificación</span>
              <span className="badge" style={{ background: VERIFICACION_COLOR[c.estadoVerificacion] || '#999', color: c.estadoVerificacion === 'pendiente' ? '#000' : '#fff', padding: '4px 12px', borderRadius: 12, fontWeight: 'bold' }}>
                {c.estadoVerificacion?.toUpperCase() || 'PENDIENTE'}
              </span>
            </div>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Disponible</span><span style={styles.perfilValor}>{c.disponible ? '✅ Sí' : '🔴 No'}</span></div>
            <div style={styles.perfilItem}><span style={styles.perfilLabel}>Registro</span><span style={styles.perfilValor}>{new Date(c.creadoEn).toLocaleDateString('es-CO')}</span></div>
          </div>

          <h3 style={{ marginTop: 24, marginBottom: 16, fontSize: 16 }}>Documentos adjuntos</h3>
          <div style={styles.docsGrid}>
            {[
              { key: 'cedulaFrente',     label: 'Cédula (frente)' },
              { key: 'cedulaReverso',    label: 'Cédula (reverso)' },
              { key: 'licencia',         label: 'Licencia de conducción' },
              { key: 'tarjetaPropiedad', label: 'Tarjeta de propiedad' },
              { key: 'tarjetaOperacion', label: 'Tarjeta de operación' },
              { key: 'tarjeton',         label: 'Tarjetón' },
            ].map(({ key, label }) => (
              <div key={key} style={styles.docItem}>
                <p style={styles.docLabel}>{label}</p>
                {c.documentos?.[key]
                  ? <img src={c.documentos[key]} alt={label} style={styles.docImg} />
                  : <div style={styles.docVacio}>Sin imagen</div>
                }
              </div>
            ))}
          </div>

          {c.estadoVerificacion === 'pendiente' && (
            <div style={styles.accionesVerif}>
              <button style={styles.btnAprobar} onClick={() => verificar(c.uid, 'aprobado')}>
                ✅ Aprobar conductor
              </button>
              <button style={styles.btnRechazar} onClick={() => verificar(c.uid, 'rechazado')}>
                ❌ Rechazar
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  const exportarUsuariosCSV = () => {
    const headers = ['Nombre', 'Cédula', 'Celular', 'Rol', 'Placa', 'Verificación', 'Disponible', 'Registro'];
    const filas = filtrados.map(u => [
      u.nombre || '',
      u.cedula || '',
      u.telefono || '',
      u.rol || '',
      u.placa || '',
      u.estadoVerificacion || '',
      u.rol === 'conductor' ? (u.disponible ? 'Sí' : 'No') : '',
      new Date(u.creadoEn).toLocaleDateString('es-CO'),
    ]);
    const csv = [headers.join(','), ...filas.map(f => f.join(','))].join('\n');
    const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `usuarios_untaxtame_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <h2 className="titulo" style={{ marginBottom: 0 }}>
          Usuarios Registrados
          {pendientesVerificacion > 0 && (
            <span style={styles.alertaBadge}>{pendientesVerificacion} pendientes de verificación</span>
          )}
        </h2>
        <button onClick={exportarUsuariosCSV} style={{
          background: '#2E7D32', color: '#fff', border: 'none',
          borderRadius: 8, padding: '10px 20px', cursor: 'pointer',
          fontWeight: 'bold', fontSize: 14,
        }}>
          📥 Exportar CSV
        </button>
      </div>

      <div className="stats">
        <div className="stat-card"><div className="num">{usuarios.length}</div><div className="label">Total</div></div>
        <div className="stat-card"><div className="num">{usuarios.filter(u => u.rol === 'cliente').length}</div><div className="label">Clientes</div></div>
        <div className="stat-card"><div className="num">{usuarios.filter(u => u.rol === 'conductor').length}</div><div className="label">Conductores</div></div>
        <div className="stat-card"><div className="num">{pendientesVerificacion}</div><div className="label">Por verificar</div></div>
      </div>

      <div style={{ marginBottom: 16, display: 'flex', gap: 8 }}>
        {['todos', 'cliente', 'conductor'].map(f => (
          <button key={f} onClick={() => setFiltro(f)} style={{
            padding: '8px 18px', borderRadius: 8, border: '2px solid #FFC107',
            background: filtro === f ? '#FFC107' : '#fff',
            fontWeight: 'bold', cursor: 'pointer'
          }}>
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      <table>
        <thead>
          <tr>
            <th>Nombre</th>
            <th>Cédula</th>
            <th>Celular</th>
            <th>Rol</th>
            <th>Placa</th>
            <th>Verificación</th>
            <th>Disponible</th>
            <th>Acciones</th>
          </tr>
        </thead>
        <tbody>
          {filtrados.length === 0 && (
            <tr><td colSpan="8" style={{ textAlign: 'center', color: '#999' }}>Sin usuarios</td></tr>
          )}
          {filtrados.map(u => (
            <tr key={u.uid}>
              <td>{u.nombre}</td>
              <td>{u.cedula || '—'}</td>
              <td>{u.telefono}</td>
              <td><span className={`badge ${u.rol}`}>{u.rol}</span></td>
              <td>{u.placa || '—'}</td>
              <td>
                {u.rol === 'conductor'
                  ? <span style={{ background: VERIFICACION_COLOR[u.estadoVerificacion] || '#999', color: u.estadoVerificacion === 'pendiente' ? '#000' : '#fff', padding: '3px 10px', borderRadius: 10, fontSize: 12, fontWeight: 'bold' }}>
                      {u.estadoVerificacion?.toUpperCase() || 'PENDIENTE'}
                    </span>
                  : '—'
                }
              </td>
              <td>{u.rol === 'conductor' ? (u.disponible ? '✅' : '🔴') : '—'}</td>
              <td>
                {u.rol === 'conductor' && (
                  <button onClick={() => setConductorSeleccionado(u)} style={styles.btnVer}>
                    Ver perfil
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

const styles = {
  alertaBadge: {
    marginLeft: 12, background: '#FFC107', color: '#000',
    padding: '4px 12px', borderRadius: 12, fontSize: 13, fontWeight: 'bold'
  },
  btnVolver: {
    background: 'none', border: 'none', color: '#E53935',
    cursor: 'pointer', fontSize: 15, marginBottom: 16, fontWeight: 'bold'
  },
  btnVer: {
    background: '#1565C0', color: '#fff', border: 'none',
    borderRadius: 6, padding: '6px 12px', cursor: 'pointer', fontSize: 13
  },
  perfilCard: {
    background: '#fff', borderRadius: 16, padding: 28,
    boxShadow: '0 2px 12px rgba(0,0,0,0.08)'
  },
  perfilGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 },
  perfilItem: { display: 'flex', flexDirection: 'column', gap: 4 },
  perfilLabel: { fontSize: 12, color: '#999', textTransform: 'uppercase', letterSpacing: 0.5 },
  perfilValor: { fontSize: 16, fontWeight: '600', color: '#222' },
  docsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 },
  docItem: { background: '#f9f9f9', borderRadius: 10, padding: 12 },
  docLabel: { fontSize: 13, fontWeight: '600', marginBottom: 8, color: '#444' },
  docImg: { width: '100%', height: 120, objectFit: 'cover', borderRadius: 8 },
  docVacio: {
    height: 120, background: '#eee', borderRadius: 8,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: '#999', fontSize: 13
  },
  accionesVerif: { display: 'flex', gap: 12, marginTop: 24 },
  btnAprobar: {
    background: '#2E7D32', color: '#fff', border: 'none',
    borderRadius: 8, padding: '12px 28px', cursor: 'pointer',
    fontWeight: 'bold', fontSize: 15
  },
  btnRechazar: {
    background: '#E53935', color: '#fff', border: 'none',
    borderRadius: 8, padding: '12px 28px', cursor: 'pointer',
    fontWeight: 'bold', fontSize: 15
  },
};
